        ):
            if value is not None and (
                not isinstance(value, int) or isinstance(value, bool)
            ):
                raise TypeError(f"{name} must be an int or None")
            if value is not None and value < 0:
                raise ValueError(f"{name} must not be negative")
        self.max_cookies, self.max_cookies_per_domain = (
            max_cookies,
            max_cookies_per_domain,
        )
        self._cookies: dict[tuple[str, str, str], _StoredCookie] = {}
        self._created = 0
        if cookies is not None:
            self.update(cookies)

    @staticmethod
    def _domain_matches(host: str, domain: str) -> bool:
        domain = domain.lower().lstrip(".")
        return host.lower() == domain or host.lower().endswith("." + domain)

    @staticmethod
    def _default_path(path: str) -> str:
        return (
            "/"
            if not path.startswith("/") or path.count("/") <= 1
            else path.rsplit("/", 1)[0] or "/"
        )

    @staticmethod
    def _path_matches(request_path: str, cookie_path: str) -> bool:
        return request_path == cookie_path or (
            request_path.startswith(cookie_path)
